#!/bin/bash
gh api graphql --paginate -F owner="aaronjmars" -f query='query($owner: String!, $endCursor: String) { repositoryOwner(login: $owner) { repositories(first: 100, after: $endCursor, orderBy: {field: PUSHED_AT, direction: DESC}, ownerAffiliations: OWNER) { pageInfo { hasNextPage endCursor } nodes { name url description pushedAt updatedAt createdAt isArchived isFork isTemplate isPrivate isEmpty stargazerCount forkCount diskUsage primaryLanguage { name } languages(first: 5, orderBy: {field: SIZE, direction: DESC}) { nodes { name } } repositoryTopics(first: 10) { nodes { topic { name } } } licenseInfo { spdxId } defaultBranchRef { name } issues(states: OPEN) { totalCount } pullRequests(states: OPEN) { totalCount } readme: object(expression: "HEAD:README.md") { ... on Blob { byteSize text } } claudemd: object(expression: "HEAD:CLAUDE.md") { ... on Blob { byteSize } } license_file: object(expression: "HEAD:LICENSE") { ... on Blob { byteSize } } dependabot: object(expression: "HEAD:.github/dependabot.yml") { ... on Blob { byteSize } } contributing: object(expression: "HEAD:CONTRIBUTING.md") { ... on Blob { byteSize } } workflows: object(expression: "HEAD:.github/workflows") { ... on Tree { entries { name } } } packagejson: object(expression: "HEAD:package.json") { ... on Blob { text } } cargotoml: object(expression: "HEAD:Cargo.toml") { ... on Blob { byteSize } } gomod: object(expression: "HEAD:go.mod") { ... on Blob { byteSize } } pyproject: object(expression: "HEAD:pyproject.toml") { ... on Blob { byteSize } } requirements: object(expression: "HEAD:requirements.txt") { ... on Blob { byteSize } } foundry: object(expression: "HEAD:foundry.toml") { ... on Blob { byteSize } } hardhat: object(expression: "HEAD:hardhat.config.js") { ... on Blob { byteSize } } } } } }' > "$1"
